import { createServer } from '@replit/river';
import { createServiceSchema, Procedure, Ok } from '@replit/river';
import { WebSocketServerTransport } from '@replit/river/transport/ws/server';
import { WebSocketServer, WebSocket } from 'ws';
import type { Server } from 'http';
import { sessionManager } from './session-manager';
import { storage } from './storage';
import * as schema from '@shared/river-schema';

// Map to track WebSocket connections by user ID
// Using a Set to support multiple connections from the same user (multiple tabs)
const userConnections = new Map<string, Set<WebSocket>>();
const connectionToUser = new Map<WebSocket, string>();

function addUserConnection(userId: string, ws: WebSocket) {
  let connections = userConnections.get(userId);
  if (!connections) {
    connections = new Set();
    userConnections.set(userId, connections);
  }
  connections.add(ws);
}

function removeUserConnection(userId: string, ws: WebSocket) {
  const connections = userConnections.get(userId);
  if (connections) {
    connections.delete(ws);
    if (connections.size === 0) {
      userConnections.delete(userId);
      return true; // No more connections for this user
    }
  }
  return false; // Still has other connections
}

function getUserConnection(userId: string): WebSocket | undefined {
  const connections = userConnections.get(userId);
  if (connections && connections.size > 0) {
    // Return the first active connection
    for (const ws of Array.from(connections)) {
      if (ws.readyState === WebSocket.OPEN) {
        return ws;
      }
    }
  }
  return undefined;
}

function broadcastToUser(userId: string, message: string) {
  const connections = userConnections.get(userId);
  if (connections) {
    for (const ws of Array.from(connections)) {
      if (ws.readyState === WebSocket.OPEN) {
        ws.send(message);
      }
    }
  }
}

// Service schema for focus session operations
const SessionServiceSchema = createServiceSchema();

export const SessionService = SessionServiceSchema.define(
  {
    initializeState: () => ({ connectedAt: Date.now() }),
  },
  {
    // Join the random matching queue with session type
    joinQueue: Procedure.rpc({
      requestInit: schema.JoinQueueRequest,
      responseData: schema.JoinQueueResponse,
      async handler({ reqInit }) {
        const result = await sessionManager.joinQueue(reqInit.userId, reqInit.sessionType);
        return Ok(result);
      },
    }),

    // Leave the queue
    leaveQueue: Procedure.rpc({
      requestInit: schema.LeaveQueueRequest,
      responseData: schema.LeaveQueueResponse,
      async handler({ reqInit }) {
        const success = sessionManager.leaveQueue(reqInit.userId);
        return Ok({ success });
      },
    }),

    // Heartbeat to keep connection alive
    heartbeat: Procedure.rpc({
      requestInit: schema.HeartbeatRequest,
      responseData: schema.HeartbeatResponse,
      async handler({ reqInit }) {
        sessionManager.registerUser(reqInit.userId);
        const acknowledged = sessionManager.heartbeat(reqInit.userId);
        return Ok({ acknowledged, serverTime: Date.now() });
      },
    }),

    // Disconnect and cleanup
    disconnect: Procedure.rpc({
      requestInit: schema.DisconnectRequest,
      responseData: schema.DisconnectResponse,
      async handler({ reqInit }) {
        await sessionManager.disconnect(reqInit.userId);
        return Ok({ success: true });
      },
    }),

    // Send WebRTC signal to partner(s) - supports both 1-on-1 and mesh routing
    sendSignal: Procedure.rpc({
      requestInit: schema.SendSignalRequest,
      responseData: schema.SendSignalResponse,
      async handler({ reqInit }) {
        const targetId = reqInit.targetId;
        const signalPayload = JSON.stringify({
          type: 'signal',
          signal: reqInit,
        });

        if (targetId) {
          // Send to specific participant (mesh networking)
          // Use broadcastToUser which properly iterates over the Set of connections
          const connections = userConnections.get(targetId);
          if (connections && connections.size > 0) {
            let delivered = false;
            for (const ws of Array.from(connections)) {
              if (ws.readyState === WebSocket.OPEN) {
                ws.send(signalPayload);
                delivered = true;
              }
            }
            console.log(`[River] Delivered ${reqInit.type} signal to ${targetId}: ${delivered}`);
            return Ok({ delivered });
          }
          console.log(`[River] No connections found for target ${targetId}`);
          return Ok({ delivered: false });
        } else {
          // Broadcast to all other participants (for legacy 1-on-1 support)
          const participantIds = sessionManager.getSessionParticipantIds(reqInit.sessionId);
          let delivered = false;

          for (const participantId of participantIds) {
            if (participantId !== reqInit.senderId) {
              const connections = userConnections.get(participantId);
              if (connections) {
                for (const ws of Array.from(connections)) {
                  if (ws.readyState === WebSocket.OPEN) {
                    ws.send(signalPayload);
                    delivered = true;
                  }
                }
              }
            }
          }

          return Ok({ delivered });
        }
      },
    }),

    // Add friend
    addFriend: Procedure.rpc({
      requestInit: schema.AddFriendRequest,
      responseData: schema.AddFriendResponse,
      async handler({ reqInit }) {
        try {
          // Check if already friends
          const alreadyFriends = await storage.areFriends(reqInit.userId, reqInit.friendId);
          if (alreadyFriends) {
            return Ok({ success: false, message: 'Already friends' });
          }

          await storage.addFriend(reqInit.userId, reqInit.friendId);
          return Ok({ success: true });
        } catch (error) {
          return Ok({ success: false, message: String(error) });
        }
      },
    }),

    // Remove friend
    removeFriend: Procedure.rpc({
      requestInit: schema.RemoveFriendRequest,
      responseData: schema.RemoveFriendResponse,
      async handler({ reqInit }) {
        try {
          await storage.removeFriend(reqInit.userId, reqInit.friendId);
          return Ok({ success: true });
        } catch (error) {
          return Ok({ success: false });
        }
      },
    }),

    // Get friends list with online status
    getFriends: Procedure.rpc({
      requestInit: schema.GetFriendsRequest,
      responseData: schema.GetFriendsResponse,
      async handler({ reqInit }) {
        try {
          const friends = await storage.getFriends(reqInit.userId);
          const onlineStatus = sessionManager.getOnlineStatus(friends.map(f => f.id));

          const friendsWithStatus = friends.map(friend => ({
            id: friend.id,
            username: friend.username,
            profileImageUrl: friend.profileImageUrl,
            isOnline: onlineStatus.get(friend.id)?.isOnline ?? false,
            isIdle: onlineStatus.get(friend.id)?.isIdle ?? false,
          }));

          return Ok({ friends: friendsWithStatus });
        } catch (error) {
          return Ok({ friends: [] as { id: string; username: string | null; profileImageUrl: string | null; isOnline: boolean; isIdle: boolean; }[] });
        }
      },
    }),

    // Invite a friend to a session
    inviteFriend: Procedure.rpc({
      requestInit: schema.InviteFriendRequest,
      responseData: schema.InviteFriendResponse,
      async handler({ reqInit }) {
        const result = await sessionManager.inviteFriend(reqInit.userId, reqInit.friendId);
        if (result.status === 'sent') {
          return Ok({ status: 'sent', friendId: result.friendId! });
        } else if (result.status === 'offline') {
          return Ok({ status: 'offline' });
        } else {
          return Ok({ status: 'declined' });
        }
      },
    }),

    // Respond to a friend invite
    respondToInvite: Procedure.rpc({
      requestInit: schema.RespondToInviteRequest,
      responseData: schema.RespondToInviteResponse,
      async handler({ reqInit }) {
        const result = await sessionManager.respondToInvite(
          reqInit.userId,
          reqInit.inviterId,
          reqInit.accept
        );

        if (result.success && result.partner) {
          return Ok({
            success: true,
            sessionId: result.sessionId,
            partner: {
              id: result.partner.id,
              username: result.partner.username,
              profileImageUrl: result.partner.profileImageUrl,
            },
          });
        }
        return Ok({ success: result.success });
      },
    }),

    // Create a free room
    createFreeRoom: Procedure.rpc({
      requestInit: schema.CreateFreeRoomRequest,
      responseData: schema.CreateFreeRoomResponse,
      async handler({ reqInit }) {
        const result = await sessionManager.createFreeRoom(reqInit.userId, reqInit.title);
        return Ok(result);
      },
    }),

    // Join a free room
    joinFreeRoom: Procedure.rpc({
      requestInit: schema.JoinFreeRoomRequest,
      responseData: schema.JoinFreeRoomResponse,
      async handler({ reqInit }) {
        const result = await sessionManager.joinFreeRoom(reqInit.userId, reqInit.sessionId);
        return Ok({ success: result.success });
      },
    }),

    // Get available free rooms
    getFreeRooms: Procedure.rpc({
      requestInit: schema.GetFreeRoomsRequest,
      responseData: schema.GetFreeRoomsResponse,
      async handler() {
        const rooms = sessionManager.getFreeRooms();
        return Ok({ rooms });
      },
    }),

    // Leave a room
    leaveRoom: Procedure.rpc({
      requestInit: schema.LeaveRoomRequest,
      responseData: schema.LeaveRoomResponse,
      async handler({ reqInit }) {
        await sessionManager.leaveRoom(reqInit.userId, reqInit.sessionId);
        return Ok({ success: true });
      },
    }),

    // Join a scheduled session
    joinScheduledSession: Procedure.rpc({
      requestInit: schema.JoinScheduledSessionRequest,
      responseData: schema.JoinScheduledSessionResponse,
      async handler({ reqInit }) {
        const result = await sessionManager.joinScheduledSession(reqInit.userId, reqInit.sessionId);
        if (result.success) {
          return Ok({ 
            success: true, 
            participants: result.participants?.map(p => ({
              id: p.userId,
              username: p.username,
              profileImageUrl: p.profileImageUrl,
            }))
          });
        }
        return Ok({ success: false, error: result.error });
      },
    }),
  }
);

export function setupRiverServer(httpServer: Server) {
  // Create WebSocket server on a specific path
  const wss = new WebSocketServer({ 
    server: httpServer, 
    path: '/river'
  });

  // Handle connection events
  wss.on('connection', (ws, req) => {
    console.log('[River] New WebSocket connection');

    // Parse user ID from query string
    const url = new URL(req.url || '', `http://${req.headers.host}`);
    const userId = url.searchParams.get('userId');

    if (userId) {
      addUserConnection(userId, ws);
      connectionToUser.set(ws, userId);
      sessionManager.registerUser(userId);
      const connCount = userConnections.get(userId)?.size || 0;
      console.log(`[River] User ${userId} connected (${connCount} active connection(s))`);
    }

    // Handle incoming messages for signaling
    ws.on('message', async (data) => {
      try {
        const message = JSON.parse(data.toString());
        const senderId = connectionToUser.get(ws);

        if (!senderId) {
          console.warn('[River] Received message from unregistered connection');
          return;
        }

        if (message.action === 'heartbeat') {
          // Update heartbeat for the user
          sessionManager.heartbeat(senderId);
        } else if (message.action === 'joinScheduledSession' && message.sessionId) {
          // Join scheduled session and get participants
          const result = await sessionManager.joinScheduledSession(senderId, message.sessionId);

          // Send response back to the user
          ws.send(JSON.stringify({
            type: 'room-joined',
            sessionId: message.sessionId,
            success: result.success,
            error: result.error,
            participants: result.participants?.map(p => ({
              userId: p.userId,
              username: p.username,
              profileImageUrl: p.profileImageUrl,
            })) || [],
          }));

          console.log(`[River] User ${senderId} join scheduled session result: ${result.success}`);
        } else if (message.action === 'sendSignal' && message.sessionId) {
          // Get all participants in this session
          const participantIds = sessionManager.getSessionParticipantIds(message.sessionId);
          const targetId = message.targetId; // For WebRTC, we need to know who the signal is for

          const signalPayload = JSON.stringify({
            type: 'signal',
            signal: {
              type: message.type,
              sessionId: message.sessionId,
              senderId: senderId,
              data: message.data,
            },
          });

          if (targetId) {
            // Send to specific participant (for WebRTC signaling)
            broadcastToUser(targetId, signalPayload);
            console.log(`[River] Forwarded ${message.type} signal from ${senderId} to ${targetId}`);
          } else {
            // Broadcast to all other participants (for general messages)
            for (const participantId of participantIds) {
              if (participantId !== senderId) {
                broadcastToUser(participantId, signalPayload);
              }
            }
            console.log(`[River] Broadcast ${message.type} from ${senderId} to ${participantIds.length - 1} participants`);
          }
        }
      } catch (error) {
        console.error('[River] Error handling message:', error);
      }
    });

    ws.on('close', async () => {
      const disconnectedUserId = connectionToUser.get(ws);
      if (disconnectedUserId) {
        connectionToUser.delete(ws);
        const noMoreConnections = removeUserConnection(disconnectedUserId, ws);

        if (noMoreConnections) {
          // Only disconnect from session manager when ALL tabs are closed
          await sessionManager.disconnect(disconnectedUserId);
          console.log(`[River] User ${disconnectedUserId} fully disconnected (no more connections)`);
        } else {
          const remainingCount = userConnections.get(disconnectedUserId)?.size || 0;
          console.log(`[River] User ${disconnectedUserId} closed one connection (${remainingCount} remaining)`);
        }
      }
    });

    ws.on('error', (error) => {
      console.error('[River] WebSocket error:', error);
    });
  });

  // Set up event callback for session manager
  sessionManager.setEventCallback((userId: string, event: any) => {
    broadcastToUser(userId, JSON.stringify(event));
  });

  // Note: We're using raw WebSocket for messaging, not River RPC
  // The River service schema is defined above for documentation purposes
  // but we handle WebSocket messages directly in the 'message' event handler

  console.log('[River] Server initialized');

  return wss;
}

export type RiverServer = ReturnType<typeof setupRiverServer>;
export type SessionServiceType = typeof SessionService;

