import { useState } from "react";
import { useLocation } from "wouter";
import { useAuth } from "@/hooks/useAuth";
import { useQuery, useMutation } from "@tanstack/react-query";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Loader2, Plus, Users, ArrowLeft, RefreshCw } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

interface FreeRoom {
  sessionId: string;
  title: string;
  participantCount: number;
  maxCapacity: number;
  hostId: string;
}

export default function FreeRooms() {
  const { user, isLoading: authLoading } = useAuth();
  const [, setLocation] = useLocation();
  const [createDialogOpen, setCreateDialogOpen] = useState(false);
  const [roomTitle, setRoomTitle] = useState("");
  const { toast } = useToast();

  const { data, isLoading, refetch } = useQuery<{ rooms: FreeRoom[] }>({
    queryKey: ['/api/free-rooms'],
    refetchInterval: 5000, // Refresh every 5 seconds
  });

  const createRoomMutation = useMutation({
    mutationFn: async (title: string) => {
      return apiRequest("POST", "/api/free-rooms", { title });
    },
    onSuccess: (data: any) => {
      console.log('[FreeRooms] Create room response:', data);
      queryClient.invalidateQueries({ queryKey: ['/api/free-rooms'] });
      setCreateDialogOpen(false);
      setRoomTitle("");

      // Extract sessionId from response
      const sessionId = data?.sessionId || data?.data?.sessionId;

      if (!sessionId) {
        console.error('[FreeRooms] No sessionId in response:', data);
        toast({
          variant: "destructive",
          title: "Error",
          description: "Failed to get session ID from server.",
        });
        return;
      }

      // Navigate to session page
      toast({
        title: "Room Created",
        description: "Your free room has been created. Connecting...",
      });

      setTimeout(() => {
        console.log('[FreeRooms] Navigating to session:', sessionId);
        setLocation(`/session/${sessionId}`);
      }, 500);
    },
    onError: () => {
      toast({
        variant: "destructive",
        title: "Error",
        description: "Failed to create room. Please try again.",
      });
    },
  });

  const joinRoomMutation = useMutation({
    mutationFn: async (sessionId: string) => {
      return apiRequest("POST", `/api/free-rooms/${sessionId}/join`, {});
    },
    onSuccess: (data: any, sessionId: string) => {
      if (data.success) {
        toast({
          title: "Joining Room",
          description: "Connecting to room...",
        });

        setTimeout(() => {
          setLocation(`/session/${sessionId}`);
        }, 500);
      } else {
        toast({
          variant: "destructive",
          title: "Failed to Join",
          description: "Room is full or no longer available.",
        });
      }
    },
    onError: () => {
      toast({
        variant: "destructive",
        title: "Error",
        description: "Failed to join room. Please try again.",
      });
    },
  });

  const handleCreateRoom = () => {
    if (!roomTitle.trim()) {
      toast({
        variant: "destructive",
        title: "Title Required",
        description: "Please enter a room title.",
      });
      return;
    }

    createRoomMutation.mutate(roomTitle);
  };

  const handleJoinRoom = (sessionId: string) => {
    joinRoomMutation.mutate(sessionId);
  };

  if (authLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  const rooms = data?.rooms || [];

  return (
    <div className="min-h-screen bg-background">
      <header className="border-b">
        <div className="max-w-6xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Button 
              variant="ghost" 
              size="icon"
              onClick={() => setLocation("/")}
              data-testid="button-back"
            >
              <ArrowLeft className="h-5 w-5" />
            </Button>
            <h1 className="text-2xl font-semibold">Free Rooms</h1>
          </div>

          <div className="flex items-center gap-2">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setLocation("/profile")}
              className="rounded-full"
              data-testid="button-profile"
            >
              <Avatar className="h-9 w-9">
                <AvatarImage src={user?.profileImageUrl || undefined} />
                <AvatarFallback>
                  {user?.firstName && user?.lastName
                    ? `${user.firstName[0]}${user.lastName[0]}`
                    : user?.username?.[0]?.toUpperCase() || "?"}
                </AvatarFallback>
              </Avatar>
            </Button>
            <Button
              variant="ghost"
              size="icon"
              onClick={() => refetch()}
              disabled={isLoading}
              data-testid="button-refresh"
            >
              <RefreshCw className={`h-5 w-5 ${isLoading ? 'animate-spin' : ''}`} />
            </Button>

            <Dialog open={createDialogOpen} onOpenChange={setCreateDialogOpen}>
              <DialogTrigger asChild>
                <Button data-testid="button-create-room">
                  <Plus className="mr-2 h-4 w-4" />
                  Create Room
                </Button>
              </DialogTrigger>
              <DialogContent>
                <DialogHeader>
                  <DialogTitle>Create a Free Room</DialogTitle>
                  <DialogDescription>
                    Create an open room where up to 10 people can join and work together.
                  </DialogDescription>
                </DialogHeader>
                <div className="space-y-4 py-4">
                  <div className="space-y-2">
                    <Label htmlFor="room-title">Room Title</Label>
                    <Input
                      id="room-title"
                      placeholder="Enter room title"
                      value={roomTitle}
                      onChange={(e) => setRoomTitle(e.target.value)}
                      data-testid="input-room-title"
                    />
                  </div>
                </div>
                <DialogFooter>
                  <Button
                    variant="ghost"
                    onClick={() => setCreateDialogOpen(false)}
                    data-testid="button-cancel-create"
                  >
                    Cancel
                  </Button>
                  <Button
                    onClick={handleCreateRoom}
                    disabled={createRoomMutation.isPending}
                    data-testid="button-confirm-create"
                  >
                    {createRoomMutation.isPending ? (
                      <>
                        <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                        Creating...
                      </>
                    ) : (
                      "Create Room"
                    )}
                  </Button>
                </DialogFooter>
              </DialogContent>
            </Dialog>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8">
        {isLoading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
          </div>
        ) : rooms.length === 0 ? (
          <div className="text-center py-12">
            <Users className="h-12 w-12 mx-auto mb-4 text-muted-foreground" />
            <h3 className="text-lg font-medium mb-2">No Active Rooms</h3>
            <p className="text-sm text-muted-foreground mb-6">
              Be the first to create a free room for focused work!
            </p>
            <Button onClick={() => setCreateDialogOpen(true)} data-testid="button-create-first-room">
              <Plus className="mr-2 h-4 w-4" />
              Create First Room
            </Button>
          </div>
        ) : (
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-4">
            {rooms.map((room) => (
              <Card 
                key={room.sessionId} 
                className="hover-elevate"
                data-testid={`card-room-${room.sessionId}`}
              >
                <CardHeader className="pb-3">
                  <div className="flex items-start justify-between gap-2">
                    <CardTitle className="text-lg">{room.title}</CardTitle>
                    <Badge 
                      variant={room.participantCount >= room.maxCapacity * 0.8 ? "destructive" : "secondary"}
                      data-testid={`badge-capacity-${room.sessionId}`}
                    >
                      {room.participantCount}/{room.maxCapacity}
                    </Badge>
                  </div>
                </CardHeader>
                <CardContent>
                  <div className="flex items-center gap-2 text-sm text-muted-foreground mb-4">
                    <Users className="h-4 w-4" />
                    <span>
                      {room.participantCount} {room.participantCount === 1 ? 'participant' : 'participants'}
                    </span>
                  </div>

                  <Button 
                    className="w-full"
                    onClick={() => handleJoinRoom(room.sessionId)}
                    disabled={
                      joinRoomMutation.isPending || 
                      room.participantCount >= room.maxCapacity ||
                      room.hostId === user?.id
                    }
                    data-testid={`button-join-${room.sessionId}`}
                  >
                    {joinRoomMutation.isPending ? (
                      <>
                        <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                        Joining...
                      </>
                    ) : room.participantCount >= room.maxCapacity ? (
                      "Room Full"
                    ) : room.hostId === user?.id ? (
                      "Your Room"
                    ) : (
                      "Join Room"
                    )}
                  </Button>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </main>
    </div>
  );
}

client/src/components/notification-bell..content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Bell, X, Check } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { ScrollArea } from "@/components/ui/scroll-area";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { formatDistanceToNow } from "date-fns";
import type { Notification } from "@shared/schema";

export function NotificationBell() {
  const [isOpen, setIsOpen] = useState(false);

  // Fetch unread count
  const { data: unreadData } = useQuery<{ count: number }>({
    queryKey: ["/api", "notifications", "unread-count"],
    refetchInterval: 30000, // Refetch every 30 seconds
  });

  // Fetch notifications when dropdown opens
  const { data: notifications = [] } = useQuery<Notification[]>({
    queryKey: ["/api", "notifications"],
    enabled: isOpen,
  });

  const markAsReadMutation = useMutation({
    mutationFn: async (notificationId: string) => {
      return apiRequest("PATCH", `/api/notifications/${notificationId}/read`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api", "notifications"] });
      queryClient.invalidateQueries({ queryKey: ["/api", "notifications", "unread-count"] });
    },
  });

  const markAllReadMutation = useMutation({
    mutationFn: async () => {
      return apiRequest("PATCH", "/api/notifications/mark-all-read");
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api", "notifications"] });
      queryClient.invalidateQueries({ queryKey: ["/api", "notifications", "unread-count"] });
    },
  });

  const unreadCount = unreadData?.count || 0;

  const getNotificationIcon = (type: string) => {
    return null; // Icons can be added based on type if needed
  };

  const getNotificationColor = (type: string) => {
    switch (type) {
      case 'match_found':
        return 'bg-blue-500/10 border-l-blue-500';
      case 'partner_joined':
        return 'bg-green-500/10 border-l-green-500';
      case 'partner_left':
      case 'partner_canceled':
        return 'bg-orange-500/10 border-l-orange-500';
      default:
        return 'bg-muted border-l-muted-foreground';
    }
  };

  return (
    <DropdownMenu open={isOpen} onOpenChange={setIsOpen}>
      <DropdownMenuTrigger asChild>
        <Button 
          variant="ghost" 
          size="icon" 
          className="relative" 
          data-testid="button-notifications"
        >
          <Bell className="h-5 w-5" />
          {unreadCount > 0 && (
            <span 
              className="absolute top-0 right-0 flex h-5 min-w-[20px] -translate-y-1/2 translate-x-1/2 items-center justify-center rounded-full bg-destructive px-1 text-[10px] font-medium text-destructive-foreground"
              data-testid="badge-notification-count"
            >
              {unreadCount > 9 ? '9+' : unreadCount}
            </span>
          )}
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-80 p-0">
        <div className="flex items-center justify-between p-4 border-b">
          <h3 className="font-medium">Notifications</h3>
          {unreadCount > 0 && (
            <Button
              variant="ghost"
              size="sm"
              className="h-7 text-xs"
              onClick={() => markAllReadMutation.mutate()}
              disabled={markAllReadMutation.isPending}
              data-testid="button-mark-all-read"
            >
              <Check className="h-3 w-3 mr-1" />
              Mark all read
            </Button>
          )}
        </div>

        <ScrollArea className="h-[400px]">
          {notifications.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-12 px-4 text-center">
              <Bell className="h-12 w-12 text-muted-foreground mb-3 opacity-50" />
              <p className="text-sm text-muted-foreground">No notifications yet</p>
              <p className="text-xs text-muted-foreground mt-1">
                We'll notify you when something happens
              </p>
            </div>
          ) : (
            <div className="divide-y">
              {notifications.map((notification) => (
                <div
                  key={notification.id}
                  className={`p-4 hover-elevate cursor-pointer border-l-4 ${
                    notification.read === 0 ? 'bg-muted/50' : ''
                  } ${getNotificationColor(notification.type)}`}
                  onClick={() => {
                    if (notification.read === 0) {
                      markAsReadMutation.mutate(notification.id);
                    }
                  }}
                  data-testid={`notification-${notification.id}`}
                >
                  <div className="flex items-start justify-between gap-2">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <p className="text-sm font-medium">{notification.title}</p>
                        {notification.read === 0 && (
                          <span className="h-2 w-2 rounded-full bg-primary flex-shrink-0" />
                        )}
                      </div>
                      <p className="text-xs text-muted-foreground mb-2">
                        {notification.message}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        {notification.createdAt && formatDistanceToNow(new Date(notification.createdAt), { addSuffix: true })}
                      </p>
                    </div>
                    {notification.read === 0 && (
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-6 w-6 flex-shrink-0"
                        onClick={(e) => {
                          e.stopPropagation();
                          markAsReadMutation.mutate(notification.id);
                        }}
                        data-testid={`button-mark-read-${notification.id}`}
                      >
                        <X className="h-3 w-3" />
                      </Button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </ScrollArea>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

